fun solve(n: Long): Boolean {
    // Calculate the sum of digits
    var digitSum = 0
    var num = n
    while (num > 0) {
        digitSum += num % 10
        num /= 10
    }

    // Calculate the product of digits
    var digitProduct = 1
    num = n
    while (num > 0) {
        val d = num % 10
        digitProduct *= d
        num /= 10
    }

    // Check if n is divisible by the sum of the digits and the product of the digits
    return n % (digitSum + digitProduct) == 0
}
